import { performance } from 'perf_hooks';
import { transpile } from './src/betti/babelfish';
import {
  buildPolyglotFnInput,
  id,
  callArg,
  member,
  varDecl,
  ret,
  initPolyglotBettiWasm,
} from './src/betti/polyglot-betti-bridge';
import * as path from 'path';

import { createRequire } from 'node:module';
const require = createRequire(import.meta.url);

const ITERATIONS = 1000;

async function runBenchmark() {
  const wasmPath = './open-source/gnosis/gnosis-betti-wasm/pkg/gnosis_betti_wasm.js';
  console.log(`[Babelfish Benchmark] Initializing WASM from ${wasmPath}...`);
  
  const initStart = performance.now();
  await initPolyglotBettiWasm(wasmPath);
  const initEnd = performance.now();
  console.log(`[Babelfish Benchmark] WASM loaded in ${(initEnd - initStart).toFixed(2)}ms\n`);

  const input = buildPolyglotFnInput(
    'python',
    'heavy_compute_pipeline',
    ['dataset', 'config'],
    [
      varDecl(['cleaned'], callArg(member(id('dataset'), 'filter'), [id('config')])),
      varDecl(['mapped'], callArg(id('apply_transform'), [id('cleaned')])),
      varDecl(['reduced'], callArg(id('aggregate'), [id('mapped')])),
      ret(id('reduced'))
    ]
  );

  const targets = [
    'python', 'go', 'rust', 'gnot',
    'c', 'cpp', 'csharp', 'elixir', 'fsharp', 'haskell',
    'java', 'javascript', 'kotlin', 'lean', 'lua', 'ocaml',
    'php', 'ruby', 'scala', 'swift', 'typescript', 'zig'
  ];

  console.log(`Running generative transpilation benchmark for ${ITERATIONS} iterations per language...\n`);
  
  for (const target of targets) {
    let totalTime = 0;
    
    // Warmup
    try { transpile(input, { targetLanguage: target }); } catch(e) {}
    
    for (let i = 0; i < ITERATIONS; i++) {
        const start = performance.now();
        try {
            transpile(input, { targetLanguage: target });
        } catch (e) {
            // some dummy languages fallback and throw errors
        }
        totalTime += (performance.now() - start);
    }
    
    console.log(`  - Target: ${target.padEnd(12)} | Avg Time: ${(totalTime / ITERATIONS).toFixed(4)}ms per transpilation`);
  }
}

runBenchmark().catch(console.error);
